"use client";

import { useState, useEffect, useMemo } from "react";
import { useParams, useRouter } from "next/navigation";
import StatViewToggle from "@/components/stat-view-toggle";
import TableViewToggle from "@/components/table-view-toggle";
import DataTable from "@/components/data-table";
import {
  rosterOverviewColumns,
  rosterKrColumns,
  teamOverallColumns,
  opponentOverallColumns,
  comparisonColumns,
  splitColumns,
  gameByGameColumns,
  simpleGameLogColumns,
  gameHighsColumns,
} from "@/lib/columns";
import { fmtPct, fmtDec } from "@/lib/stats";
import type {
  StatView,
  TableView,
  Player,
  PlayerSeasonTotals,
  PlayerKR,
  Team,
  TeamSeasonTotals,
  TeamGameTotals,
  TeamSplitRow,
  GameHighRow,
} from "@/lib/types";

type Tab = "roster" | "teamStats" | "gameLog";
type StatsSubView = "teamOverall" | "oppOverall" | "comparison" | "splits" | "gameByGame" | "gameHighs";
type PlayerRow = Player & PlayerSeasonTotals;
type PlayerKRRow = Player & PlayerSeasonTotals & PlayerKR;

const TABS: { key: Tab; label: string }[] = [
  { key: "roster", label: "Roster" },
  { key: "teamStats", label: "Team Stats" },
  { key: "gameLog", label: "Game Log" },
];

const STATS_SUBS: { key: StatsSubView; label: string }[] = [
  { key: "teamOverall", label: "Team Overall" },
  { key: "oppOverall", label: "Opponent Overall" },
  { key: "comparison", label: "Comparison" },
  { key: "splits", label: "Splits" },
  { key: "gameByGame", label: "Game-by-Game" },
  { key: "gameHighs", label: "Game Highs" },
];

const NULL_KR_FIELDS = {
  kr: null, krOff: null, krDef: null,
  krShooting: null, krFinishing: null, krPlaymaking: null,
  krPoaDefense: null, krTeamDefense: null, krRebounding: null,
  krTools: null, krIq: null,
  archetype: null, confidence: null,
} as const;

export default function TeamPage() {
  const params = useParams();
  const router = useRouter();
  const teamId = params.teamId as string;

  const [tab, setTab] = useState<Tab>("roster");
  const [statsSubView, setStatsSubView] = useState<StatsSubView>("teamOverall");
  const [rosterTableView, setRosterTableView] = useState<TableView>("overview");
  const [rosterStatView, setRosterStatView] = useState<StatView>("perGame");
  const [statsStatView, setStatsStatView] = useState<StatView>("perGame");
  const [loading, setLoading] = useState(true);

  const [team, setTeam] = useState<Team | null>(null);
  const [roster, setRoster] = useState<PlayerRow[]>([]);
  const [teamStats, setTeamStats] = useState<TeamSeasonTotals | null>(null);
  const [opponentStats, setOpponentStats] = useState<TeamSeasonTotals | null>(null);
  const [splits, setSplits] = useState<TeamSplitRow[]>([]);
  const [gameLog, setGameLog] = useState<TeamGameTotals[]>([]);
  const [gameHighs, setGameHighs] = useState<GameHighRow[]>([]);

  useEffect(() => {
    fetch(`/api/teams/${teamId}`)
      .then((r) => r.json())
      .then((data) => {
        setTeam(data.team);
        setRoster(data.roster ?? []);
        setTeamStats(data.teamStats ?? null);
        setOpponentStats(data.opponentStats ?? null);
        setSplits(data.splits ?? []);
        setGameLog(data.gameLog ?? []);
        setGameHighs(data.gameHighs ?? []);
        setLoading(false);
      });
  }, [teamId]);

  // Roster columns
  const rosterOverviewCols = useMemo(() => rosterOverviewColumns(rosterStatView), [rosterStatView]);
  const rosterKrCols = useMemo(() => rosterKrColumns(), []);
  const rosterKrData: PlayerKRRow[] = useMemo(
    () => roster.map((r) => ({ ...r, ...NULL_KR_FIELDS })),
    [roster]
  );

  // Team stats columns
  const teamOverallCols = useMemo(() => teamOverallColumns(statsStatView), [statsStatView]);
  const oppOverallCols = useMemo(() => opponentOverallColumns(statsStatView), [statsStatView]);
  const compCols = useMemo(() => comparisonColumns(), []);
  const splitCols = useMemo(() => splitColumns(), []);
  const gameByGameCols = useMemo(() => gameByGameColumns(), []);
  const simpleGameCols = useMemo(() => simpleGameLogColumns(), []);
  const gameHighCols = useMemo(() => gameHighsColumns(), []);

  // Comparison data
  const comparisonData = useMemo(() => {
    if (!teamStats || !opponentStats) return [];
    const ts = teamStats;
    const os = opponentStats;
    return [
      { stat: "FG%", team: fmtPct(ts.fgm, ts.fga), opponent: fmtPct(os.fgm, os.fga) },
      { stat: "3P%", team: fmtPct(ts.threePm, ts.threePa), opponent: fmtPct(os.threePm, os.threePa) },
      { stat: "FT%", team: fmtPct(ts.ftm, ts.fta), opponent: fmtPct(os.ftm, os.fta) },
      { stat: "PPG", team: ts.gp ? fmtDec(ts.pts / ts.gp) : "", opponent: os.gp ? fmtDec(os.pts / os.gp) : "" },
      { stat: "RPG", team: ts.gp ? fmtDec(ts.trb / ts.gp) : "", opponent: os.gp ? fmtDec(os.trb / os.gp) : "" },
      { stat: "APG", team: ts.gp ? fmtDec(ts.ast / ts.gp) : "", opponent: os.gp ? fmtDec(os.ast / os.gp) : "" },
      { stat: "TOPG", team: ts.gp ? fmtDec(ts.to / ts.gp) : "", opponent: os.gp ? fmtDec(os.to / os.gp) : "" },
      { stat: "SPG", team: ts.gp ? fmtDec(ts.stl / ts.gp) : "", opponent: os.gp ? fmtDec(os.stl / os.gp) : "" },
      { stat: "BPG", team: ts.gp ? fmtDec(ts.blk / ts.gp) : "", opponent: os.gp ? fmtDec(os.blk / os.gp) : "" },
      { stat: "PF", team: ts.gp ? fmtDec(ts.pf / ts.gp) : "", opponent: os.gp ? fmtDec(os.pf / os.gp) : "" },
    ];
  }, [teamStats, opponentStats]);

  if (loading) {
    return <div className="text-center py-12 text-slate-400">Loading...</div>;
  }

  if (!team) {
    return <div className="text-center py-12 text-slate-400">Team not found</div>;
  }

  return (
    <>
      {/* Header */}
      <div className="mb-4">
        <h1 className="text-2xl font-bold tracking-tight">{team.name}</h1>
        <p className="text-sm text-slate-500">
          {team.level} &middot; {team.conference} &middot; {team.season}
          {team.wins != null && ` \u00b7 ${team.wins}-${team.losses}`}
        </p>
      </div>

      {/* Tabs */}
      <div className="flex items-center gap-1 border-b border-slate-200 mb-4">
        {TABS.map((t) => (
          <button
            key={t.key}
            onClick={() => setTab(t.key)}
            className={`px-4 py-2 text-sm font-medium border-b-2 transition-colors ${
              tab === t.key
                ? "border-slate-900 text-slate-900"
                : "border-transparent text-slate-400 hover:text-slate-600"
            }`}
          >
            {t.label}
          </button>
        ))}
      </div>

      {/* Roster tab */}
      {tab === "roster" && (
        <>
          <div className="flex items-center justify-end gap-4 mb-4">
            <TableViewToggle value={rosterTableView} onChange={setRosterTableView} />
            {rosterTableView === "overview" && (
              <StatViewToggle value={rosterStatView} onChange={setRosterStatView} />
            )}
          </div>
          {rosterTableView === "overview" ? (
            <DataTable
              columns={rosterOverviewCols}
              data={roster}
              defaultSortKey="ppg"
              onRowClick={(row) => router.push(`/teams/${teamId}/players/${row.id}`)}
            />
          ) : (
            <DataTable
              columns={rosterKrCols}
              data={rosterKrData}
              defaultSortKey="kr"
              onRowClick={(row) => router.push(`/teams/${teamId}/players/${row.id}`)}
            />
          )}
        </>
      )}

      {/* Team Stats tab */}
      {tab === "teamStats" && (
        <>
          <div className="flex items-center justify-between gap-4 mb-4">
            <div className="flex items-center gap-1 flex-wrap">
              {STATS_SUBS.map((s) => (
                <button
                  key={s.key}
                  onClick={() => setStatsSubView(s.key)}
                  className={`px-3 py-1 text-xs font-medium rounded-full transition-colors ${
                    statsSubView === s.key
                      ? "bg-slate-900 text-white"
                      : "bg-slate-100 text-slate-500 hover:text-slate-700"
                  }`}
                >
                  {s.label}
                </button>
              ))}
            </div>
            {(statsSubView === "teamOverall" || statsSubView === "oppOverall") && (
              <StatViewToggle value={statsStatView} onChange={setStatsStatView} />
            )}
          </div>

          {statsSubView === "teamOverall" && teamStats && (
            <DataTable columns={teamOverallCols} data={[teamStats]} />
          )}
          {statsSubView === "oppOverall" && opponentStats && (
            <DataTable columns={oppOverallCols} data={[opponentStats]} />
          )}
          {statsSubView === "comparison" && (
            <DataTable columns={compCols} data={comparisonData} />
          )}
          {statsSubView === "splits" && (
            <DataTable columns={splitCols} data={splits} />
          )}
          {statsSubView === "gameByGame" && (
            <DataTable
              columns={gameByGameCols}
              data={gameLog}
              defaultSortKey="date"
              defaultSortDir="desc"
            />
          )}
          {statsSubView === "gameHighs" && (
            <DataTable columns={gameHighCols} data={gameHighs} />
          )}
        </>
      )}

      {/* Game Log tab */}
      {tab === "gameLog" && (
        <DataTable
          columns={simpleGameCols}
          data={gameLog}
          defaultSortKey="date"
          defaultSortDir="desc"
        />
      )}
    </>
  );
}
