import type { Column } from "@/components/data-table";
import type {
  Player,
  PlayerSeasonTotals,
  PlayerKR,
  PlayerGameStats,
  StatView,
  TeamCoverage,
  TeamSeasonTotals,
  TeamGameTotals,
  TeamSplitRow,
  GameHighRow,
  CategoryLeader,
} from "./types";
import { fmtStat, fmtPct, fmtHeight, efgPct, tsPct, astTo, fmtDec, fmtInt, fmtKr } from "./stats";

/* ------------------------------------------------------------------ */
/* Shared row types                                                    */
/* ------------------------------------------------------------------ */

type PlayerRow = Player & PlayerSeasonTotals;
type PlayerKRRow = Player & PlayerSeasonTotals & PlayerKR;

/* ------------------------------------------------------------------ */
/* 1. playerOverviewColumns — 20 cols for /players Overview            */
/* ------------------------------------------------------------------ */

export function playerOverviewColumns(view: StatView): Column<PlayerRow>[] {
  const s = (val: number | null | undefined, row: PlayerRow) =>
    fmtStat(val, view, row.gp, row.min);

  return [
    { key: "name", label: "Player", group: "", sortable: false, align: "left", getValue: (r) => r.name },
    { key: "team", label: "Team", group: "", sortable: false, align: "left", getValue: (r) => r.teamName },
    { key: "level", label: "Level", group: "", sortable: false, getValue: (r) => r.level },
    { key: "conf", label: "Conf", group: "", sortable: false, getValue: (r) => r.conference },
    { key: "pos", label: "Pos", group: "", sortable: false, getValue: (r) => r.position },
    { key: "ht", label: "Ht", group: "", getValue: (r) => fmtHeight(r.heightInches), getSortValue: (r) => r.heightInches ?? 0 },
    { key: "class", label: "Class", group: "", sortable: false, getValue: (r) => r.classYear },
    { key: "gp", label: "GP", group: "Games", getValue: (r) => fmtInt(r.gp), getSortValue: (r) => r.gp },
    { key: "gs", label: "GS", group: "Games", getValue: (r) => fmtInt(r.gs), getSortValue: (r) => r.gs },
    { key: "min", label: "MIN", group: "Games", getValue: (r) => s(r.min, r), getSortValue: (r) => r.min },
    { key: "mpg", label: "MPG", group: "Games", getValue: (r) => r.gp ? fmtDec(r.min / r.gp) : "", getSortValue: (r) => r.gp ? r.min / r.gp : 0 },
    { key: "pts", label: "PTS", group: "Scoring", getValue: (r) => s(r.pts, r), getSortValue: (r) => r.pts },
    { key: "ppg", label: "PPG", group: "Scoring", getValue: (r) => r.gp ? fmtDec(r.pts / r.gp) : "", getSortValue: (r) => r.gp ? r.pts / r.gp : 0 },
    { key: "trb", label: "TRB", group: "Rebounds", getValue: (r) => s(r.trb, r), getSortValue: (r) => r.trb },
    { key: "rpg", label: "RPG", group: "Rebounds", getValue: (r) => r.gp ? fmtDec(r.trb / r.gp) : "", getSortValue: (r) => r.gp ? r.trb / r.gp : 0 },
    { key: "ast", label: "AST", group: "Playmaking", getValue: (r) => s(r.ast, r), getSortValue: (r) => r.ast },
    { key: "apg", label: "APG", group: "Playmaking", getValue: (r) => r.gp ? fmtDec(r.ast / r.gp) : "", getSortValue: (r) => r.gp ? r.ast / r.gp : 0 },
    { key: "fgPct", label: "FG%", group: "Shooting", getValue: (r) => fmtPct(r.fgm, r.fga), getSortValue: (r) => r.fga ? r.fgm / r.fga : 0 },
    { key: "3pPct", label: "3P%", group: "Shooting", getValue: (r) => fmtPct(r.threePm, r.threePa), getSortValue: (r) => r.threePa ? r.threePm / r.threePa : 0 },
    { key: "ftPct", label: "FT%", group: "Shooting", getValue: (r) => fmtPct(r.ftm, r.fta), getSortValue: (r) => r.fta ? r.ftm / r.fta : 0 },
  ];
}

