/* ------------------------------------------------------------------ */
/* 3. teamCoverageColumns — 7 cols for /teams index                    */
/* ------------------------------------------------------------------ */

const STATUS_COLORS: Record<string, string> = {
  Complete: "bg-green-100 text-green-800",
  Partial: "bg-yellow-100 text-yellow-800",
  Missing: "bg-red-100 text-red-800",
};

export function teamCoverageColumns(): Column<TeamCoverage>[] {
  return [
    { key: "name", label: "Team", sortable: false, align: "left", getValue: (r) => r.name },
    { key: "level", label: "Level", sortable: false, getValue: (r) => r.level },
    { key: "conf", label: "Conference", sortable: false, getValue: (r) => r.conference },
    { key: "players", label: "Players", getValue: (r) => fmtInt(r.playerCount), getSortValue: (r) => r.playerCount },
    { key: "games", label: "Games", getValue: (r) => fmtInt(r.gameCount), getSortValue: (r) => r.gameCount },
    { key: "lastUpdated", label: "Last Updated", getValue: (r) => r.lastUpdated ?? "--", getSortValue: (r) => r.lastUpdated ?? "" },
    {
      key: "status",
      label: "Coverage",
      getValue: (r) => r.coverageStatus,
      render: (r) => (
        <span className={`px-2 py-0.5 rounded text-xs font-medium ${STATUS_COLORS[r.coverageStatus] ?? ""}`}>
          {r.coverageStatus}
        </span>
      ),
    },
  ];
}

